 const ar=[['AR inventory','818','$284k outstanding'],['Follow-ups today','126','91% completed'],['Promises to pay','34','$18.6k expected'],['Escalations','22','Needs team lead','red'],['Next action due','47','Before end of day','amber'],['Recovery rate','72.4%','↑ 5.8% this month']]
 const items=title==='Insurance Verification'?insurance:title==='Claims Follow-Up'?claims:ar
