function WorkforceQA(){return <><Head k="WORKFORCE PERFORMANCE" title="Workforce & quality assurance" sub="Attendance, utilization, productivity, and audit quality for the current week."/><MetricStrip items={[["Attendance rate","97.6%","2 late arrivals"],["Active work hours","612h","Across 18 employees"],["Utilization","86.4%","Target: 85%"],["Productivity score","92.1","↑ 3.4 points"],["QA score","96.8%","14 reviews completed"],["Open findings","7","2 high priority","red"]]}/><div className="split"><Panel title="Employee performance trends" sub="Productivity and quality combined"><Work/></Panel><Panel title="Quality audit summary" sub="Reviews completed this week"><div className="health-list"><p><span>Insurance verification accuracy</span><b className="good">98.2%</b></p><p><span>Claims documentation quality</span><b className="good">96.1%</b></p><p><span>Payment posting accuracy</span><b className="good">99.4%</b></p><p><span>Process compliance</span><b className="warn">93.8%</b></p></div></Panel></div></>}
function AuditLog({records=[]}){const rows=records.length?records:JSON.parse(localStorage.getItem('mkg-audit-log')||'[]'),today=new Date().toISOString().slice(0,10),todayRows=rows.filter(r=>String(r.at||'').slice(0,10)===today),shown=todayRows.length?todayRows:rows,fmt=iso=>iso?new Date(iso).toLocaleString(undefined,{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'}):'Unknown time';return <><Head k="COMPLIANCE" title="Audit & activity log" sub="Real user actions from task updates, imports, office edits, employee access, and reports."/><div className="filters"><button><CalendarDays/>Today</button><button><UserRound/>All users</button><button><SlidersHorizontal/>All activities</button></div><Panel title="User activity" sub={todayRows.length?'Showing today’s activity':'No activity today; showing most recent saved actions'}><div className="audit-list">{shown.length?shown.map(r=><div key={r.id}><span>{fmt(r.at)}</span><i>{String(r.user||'System').split(' ').map(x=>x[0]).join('').slice(0,2).toUpperCase()}</i><p><b>{r.user||'System'}</b><strong>{r.action}</strong><small>{r.detail}</small></p><button><MoreHorizontal/></button></div>):<div className="empty">No activity has been recorded yet. Create, import, or update a task to start the log.</div>}</div></Panel></>}
