function Offices({records,onChange}){const[edit,setEdit]=useState(null);const save=e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.currentTarget));const next=edit?.id?records.map(x=>x.id===edit.id?{...x,...v}:x):[...records,{id:'office-'+Date.now(),...v}];onChange(next,edit?.id&&edit.name!==v.name?{oldName:edit.name,newName:v.name}:null);setEdit(null)};return <><Head k="MANAGEMENT" title="Dental offices" sub="Manage client offices, contacts, and active workloads."><button className="primary" onClick={()=>setEdit({})}><Plus/>Add office</button></Head><div className="cards">{records.map((o,i)=><article key={o.id}><i>{o.name.split(' ').map(x=>x[0]).join('').slice(0,3)}</i><h3>{o.name}</h3><p>{o.location||'Location not entered'}</p><hr/><span><ClipboardList/>{42-i*7} active tasks</span><span><UserRound/>{o.provider||'Provider not entered'}</span><button onClick={()=>setEdit(o)}>Edit office <ArrowUpRight/></button></article>)}</div>{edit&&<div className="backdrop"><section className="drawer"><header><div><small>OFFICE MANAGEMENT</small><h2>{edit.id?'Edit office':'Add office'}</h2></div><button onClick={()=>setEdit(null)}><X/></button></header><form onSubmit={save}><label>Office name<input name="name" defaultValue={edit.name} required autoFocus/></label><label>Location<input name="location" defaultValue={edit.location} placeholder="City, State"/></label><label>Primary provider<input name="provider" defaultValue={edit.provider} placeholder="Dr. Name"/></label><footer><button type="button" onClick={()=>setEdit(null)}>Cancel</button><button className="primary">Save office</button></footer></form></section></div>}</>}
