function AuthScreen(){const[email,setEmail]=useState(''),[password,setPassword]=useState(''),[message,setMessage]=useState(''),[busy,setBusy]=useState(false);const login=async e=>{e.preventDefault();setBusy(true);setMessage('');const{error}=await supabase.auth.signInWithPassword({email,password});if(error)setMessage(error.message);setBusy(false)};const setup=async()=>{if(!email)return setMessage('Enter your work email first, then click Send password setup link.');setBusy(true);setMessage('');const{error}=await supabase.auth.resetPasswordForEmail(email,{redirectTo:window.location.origin+'?setup=password'});setBusy(false);setMessage(error?error.message:'Password setup link sent. Check your email.')};return <main className="auth-shell"><section className="auth-card"><div className="auth-brand"><i>M</i><span><b>MKG Operations</b><small>SECURE WORKSPACE</small></span></div><ShieldCheck className="auth-shield"/><h1>Sign in to continue</h1><p>Authorized MKG personnel only. Activity is logged and access is limited by role and assigned office.</p><form onSubmit={login}><label>Work email<input type="email" value={email} onChange={e=>setEmail(e.target.value)} required autoComplete="username"/></label><label>Password<input type="password" value={password} onChange={e=>setPassword(e.target.value)} required autoComplete="current-password"/></label>{message&&<em>{message}</em>}<button className="primary" disabled={busy}>{busy?'Please wait…':'Sign in securely'}</button><button type="button" className="link-button" onClick={setup} disabled={busy}>Send password setup link</button></form><small>New employees should open their invite, create a password, then sign in normally from any browser.</small></section></main>}
function SecureRoot(){const[session,setSession]=useState(undefined);React.useEffect(()=>{supabase.auth.getSession().then(({data})=>setSession(data.session));const{data:{subscription}}=supabase.auth.onAuthStateChange((_event,next)=>setSession(next));return()=>subscription.unsubscribe()},[]);if(session===undefined)return <div className="secure-loading"><ShieldCheck/><span>Loading secure workspace…</span></div>;return session?<App secureUser={session.user}/>:<AuthScreen/>}

function PasswordSetup({onDone}){const[password,setPassword]=useState(''),[confirm,setConfirm]=useState(''),[message,setMessage]=useState(''),[busy,setBusy]=useState(false);const save=async e=>{e.preventDefault();if(password.length<12)return setMessage('Use at least 12 characters.');if(password!==confirm)return setMessage('The passwords do not match.');setBusy(true);const{error}=await supabase.auth.updateUser({password,data:{requires_password_setup:false}});setBusy(false);if(error)return setMessage(error.message);onDone()};return <main className="auth-shell"><section className="auth-card"><div className="auth-brand"><i>M</i><span><b>MKG Operations</b><small>SECURE WORKSPACE</small></span></div><ShieldCheck className="auth-shield"/><h1>Create your password</h1><p>Set a permanent password so you can sign in from any browser.</p><form onSubmit={save}><label>New password<input type="password" value={password} onChange={e=>setPassword(e.target.value)} required minLength="12"/></label><label>Confirm password<input type="password" value={confirm} onChange={e=>setConfirm(e.target.value)} required minLength="12"/></label><small>Use 12 or more characters.</small>{message&&<em>{message}</em>}<button className="primary" disabled={busy}>{busy?'Saving...':'Save password and continue'}</button></form></section></main>}
function SecureRootWithRecovery(){const[session,setSession]=useState(undefined),[recovery,setRecovery]=useState(()=>location.hash.includes('type=recovery')||location.search.includes('type=recovery')||location.search.includes('setup=password'));React.useEffect(()=>{supabase.auth.getSession().then(({data})=>setSession(data.session));const{data:{subscription}}=supabase.auth.onAuthStateChange((event,next)=>{if(event==='PASSWORD_RECOVERY'||location.search.includes('setup=password'))setRecovery(true);setSession(next)});return()=>subscription.unsubscribe()},[]);if(session===undefined)return <div className="secure-loading"><ShieldCheck/><span>Loading secure workspace...</span></div>;if(recovery&&session)return <PasswordSetup onDone={()=>{history.replaceState(null,'',location.origin);setRecovery(false)}}/>;return session?<App secureUser={session.user}/>:<AuthScreen/>}

