function PaymentDashboard({tasks,offices,employees,open,saveTasks,allTasks,notify,logActivity}){const today=new Date().toISOString().slice(0,10),[office,setOffice]=useState('All offices'),[from,setFrom]=useState(today),[to,setTo]=useState(today),[form,setForm]=useState({date:today,postedDate:today,patient:'',insurance:'',amount:'',office:offices[0]?.name||'',employee:employees[0]?.name||''}),update=(k,v)=>setForm({...form,[k]:v}),money=t=>Number(String(t.postedAmount||0).replace(/[^0-9.-]/g,'')||0),isDone=t=>['POSTED','Completed'].includes(t.status)&&Boolean(t.postedDate),posted=tasks.filter(t=>t.postedDate&&(!from||t.postedDate>=from)&&(!to||t.postedDate<=to)&&(office==='All offices'||t.office===office)),total=posted.reduce((s,t)=>s+money(t),0),byOffice=offices.map(o=>({name:o.name,total:posted.filter(t=>t.office===o.name).reduce((s,t)=>s+money(t),0),count:posted.filter(t=>t.office===o.name).length})).filter(x=>office==='All offices'||x.name===office),byDate=Object.entries(posted.reduce((a,t)=>{a[t.postedDate]=(a[t.postedDate]||0)+money(t);return a},{})).sort((a,b)=>b[0].localeCompare(a[0])),sortedTasks=[...tasks].sort((a,b)=>Number(isDone(a))-Number(isDone(b))||String(a.due||'9999').localeCompare(String(b.due||'9999'))),add=e=>{e.preventDefault();if(!form.patient.trim())return notify('Enter patient name');if(!Number(String(form.amount).replace(/[^0-9.-]/g,'')))return notify('Enter posted amount');const task={id:'MKG-PP-'+Date.now(),patient:form.patient.trim(),office:form.office,type:'Payment Posting',employee:form.employee,priority:'Medium',status:'Completed',due:form.date,dos:form.date,followup:form.date,next:form.postedDate,completion:today,postedAmount:form.amount,postedDate:form.postedDate,notes:'Insurance: '+form.insurance+' | Posted amount: '+form.amount+' | Entry date: '+form.date+' | Posted claims sheet entry'};saveTasks([task,...allTasks]);logActivity&&logActivity('Added posted claim',task.patient+' · '+task.office+' · '+form.amount+' · posted '+form.postedDate,form.employee);setForm({...form,patient:'',insurance:'',amount:''});notify('Posted claim added')};return <><Head k="PAYMENT RECONCILIATION" title="Payment posting dashboard" sub="Defaults to today. Use posted from/through to search a specific posting date range."/><Panel title="Posted claims" sub="Add rows like the payment posting sheet. Posted date controls dashboard totals."><form className="verification-sheet-form posted-claims-form" onSubmit={add}><label>Date<input type="date" value={form.date} onChange={e=>update('date',e.target.value)} required/></label><label>Posted date<input type="date" value={form.postedDate} onChange={e=>update('postedDate',e.target.value)} required/></label><label>Pt. name<input value={form.patient} onChange={e=>update('patient',e.target.value)} required/></label><label>Insurance<input value={form.insurance} onChange={e=>update('insurance',e.target.value)} placeholder="Carrier"/></label><label>Posted amount<input value={form.amount} onChange={e=>update('amount',e.target.value)} placeholder="$0.00" required/></label><label>Office<select value={form.office} onChange={e=>update('office',e.target.value)}>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Assigned to<select value={form.employee} onChange={e=>update('employee',e.target.value)}>{employees.map(e=><option key={e.id}>{e.name}</option>)}</select></label><button className="primary"><Plus/>Add posted claim</button></form></Panel><div className="payment-filters"><label>Office<select value={office} onChange={e=>setOffice(e.target.value)}><option>All offices</option>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Posted from<input type="date" value={from} onChange={e=>setFrom(e.target.value)}/></label><label>Posted through<input type="date" value={to} onChange={e=>setTo(e.target.value)}/></label></div><MetricStrip items={[["Total posted",'$'+total.toLocaleString(undefined,{minimumFractionDigits:2}),posted.length+' transactions for selected date'],['Awaiting posting',String(tasks.filter(t=>!isDone(t)).length),'Open payment tasks']]}/><div className="split"><Panel title="Posted amount by office" sub="Today by default; filter dates to reconcile older posting"><div className="posting-summary">{byOffice.map(x=><p key={x.name}><span><b>{x.name}</b><small>{x.count} payments</small></span><strong>${x.total.toLocaleString(undefined,{minimumFractionDigits:2})}</strong></p>)}</div></Panel><Panel title="Posted amount by date" sub="Shows today by default; date filters show historical totals"><div className="posting-summary">{byDate.length?byDate.map(([date,value])=><p key={date}><span><b>{date}</b><small>Posting date</small></span><strong>${value.toLocaleString(undefined,{minimumFractionDigits:2})}</strong></p>):<div className="empty">No posted payments in this date range.</div>}</div></Panel></div><Panel title="Payment posting tasks" sub="Open tasks first. Completed/posted payments are listed at the bottom."><Table tasks={sortedTasks} open={open}/></Panel></>}

function EODV2({notify,tasks,offices,employees,logActivity}){const[employee,setEmployee]=useState(employees[0]?.name||''),[done,setDone]=useState(false),[reports,setReports]=useState(()=>JSON.parse(localStorage.getItem('mkg-eod-reports')||'[]')),today=new Date().toISOString().slice(0,10),completed=tasks.filter(t=>t.employee===employee&&['Completed','POSTED'].includes(t.status)&&[t.completion,t.postedDate].includes(today)).length;const submit=e=>{e.preventDefault();const report={id:Date.now(),date:today,employee,tasksCompleted:completed,...Object.fromEntries(new FormData(e.currentTarget)),status:'Pending review'},next=[report,...reports];setReports(next);localStorage.setItem('mkg-eod-reports',JSON.stringify(next));logActivity&&logActivity('Submitted EOD report',employee+' · '+report.office+' · '+completed+' completed tasks',employee);setDone(true);notify('EOD report saved for team lead review')};return <><Head k="DAILY REPORTING" title="End-of-day reports" sub="Completed work is calculated automatically from tasks closed today."/><div className="split"><Panel title="Submit today’s report" sub={today}>{done?<div className="success"><CheckCircle2/><h2>Report submitted</h2><p>Saved for team lead review.</p><button onClick={()=>setDone(false)}>Submit another</button></div>:<form onSubmit={submit}><label>Employee<select value={employee} onChange={e=>setEmployee(e.target.value)}>{employees.map(x=><option key={x.id}>{x.name}</option>)}</select></label><label>Office handled<select name="office">{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><div className="pair"><label>Tasks completed automatically<input value={completed} readOnly/></label><label>Time worked<input name="timeWorked" defaultValue="8 hours"/></label></div><label>Pending items<textarea name="pendingItems"/></label><label>Problem claims<textarea name="problemClaims"/></label><label>Notes or concerns<textarea name="notes"/></label><button className="primary"><Send/>Submit EOD report</button></form>}</Panel><Panel title="Submitted reports" sub="Visible to admins and team leads"><div className="eod-list">{reports.length?reports.map(r=><article key={r.id}><span><b>{r.employee}</b><small>{r.date} · {r.office}</small></span><strong>{r.tasksCompleted} tasks<small>{r.timeWorked}</small></strong><em>{r.status}</em></article>):<div className="empty">No EOD reports submitted yet.</div>}</div></Panel></div></>}

function DrawerV2({task,close,save,create,offices,employees,tasks}){const[s,setS]=useState(task?.status||'Pending'),[notes,setNotes]=useState(task?.notes||''),[employee,setEmployee]=useState(task?.employee||employees[0]?.name||''),[postedAmount,setPostedAmount]=useState(task?.postedAmount||''),[postedDate,setPostedDate]=useState(task?.postedDate||''),fresh=!task,available=task?.type==='Claims Follow-Up'?claimStatuses:task?.type==='Payment Posting'?['Pending','In Progress','Completed','Need Review']:statuses;const leastBusy=()=>{const sorted=employees.map(e=>[e.name,tasks.filter(t=>t.employee===e.name&&t.status!=='Completed').length]).sort((a,b)=>a[1]-b[1]);setEmployee(sorted[0]?.[0]||'')};return <div className="backdrop"><section className="drawer"><header><div><small>{fresh?'NEW ASSIGNMENT':task.id}</small><h2>{fresh?'Assign a task':task.patient}</h2></div><button onClick={close}><X/></button></header><form onSubmit={e=>{e.preventDefault();fresh?create({...Object.fromEntries(new FormData(e.currentTarget)),employee}):save(task,s,notes,employee,postedAmount,postedDate)}}>{fresh?<><label>Patient name<input name="patient" required/></label><label>Office<select name="office">{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Task type<select name="type"><option>Insurance Verification</option><option>Claims Follow-Up</option><option>Payment Posting</option><option>AR Follow-Up</option><option>Pre-Authorization</option></select></label><label>Due date<input name="due" type="date" required/></label><input type="hidden" name="priority" value="Medium"/><input type="hidden" name="status" value="Pending"/></>:<div className="details">{[['Office',task.office],['Task type',task.type],['Date of service',task.dos],['Current status',task.status]].map(([a,b])=><div key={a}><span>{a}</span><b>{b}</b></div>)}</div>}<label>Assign to<div className="assignment-control"><select value={employee} onChange={e=>setEmployee(e.target.value)}>{employees.map(x=><option key={x.id}>{x.name}</option>)}</select><button type="button" onClick={leastBusy}>Assign least busy</button></div></label>{!fresh&&<><label>Status<select value={s} onChange={e=>setS(e.target.value)}>{available.map(x=><option key={x}>{x}</option>)}</select></label>{task.type==='Payment Posting'&&<div className="pair"><label>Posted amount<input type="number" min="0" step="0.01" value={postedAmount} onChange={e=>setPostedAmount(e.target.value)} required={s==='Completed'} placeholder="0.00"/></label><label>Actual posting date<input type="date" value={postedDate} onChange={e=>setPostedDate(e.target.value)} required={s==='Completed'}/></label></div>}<label>Notes<textarea value={notes} onChange={e=>setNotes(e.target.value)}/></label></>}<footer><button type="button" onClick={close}>Cancel</button><button className="primary">{fresh?'Assign task':'Save changes'}</button></footer></form></section></div>}

function VerificationWorksheet({tasks,offices,employees,open,saveTasks,allTasks,notify,logActivity}){const today=new Date().toISOString().slice(0,10),[form,setForm]=useState({date:today,appt:today,patient:'',office:offices[0]?.name||'',notes:'ACTIVE INS',employee:employees[0]?.name||''}),results=['ACTIVE INS','INACTIVE INS','TERMINATED','UNABLE TO VERIFY','NEED OFFICE INFO','PENDING'];const update=(k,v)=>setForm({...form,[k]:v}),add=e=>{e.preventDefault();if(!form.patient.trim())return notify('Enter patient name');const task={id:'MKG-IV-'+Date.now(),patient:form.patient.trim(),office:form.office,type:'Insurance Verification',employee:form.employee,priority:'Medium',status:'In Progress',due:form.date,dos:form.appt,followup:'—',next:form.date,completion:'—',notes:'Verification date: '+form.date+' | Appointment date: '+form.appt+' | Result: '+form.notes};saveTasks([task,...allTasks]);logActivity&&logActivity('Added verification task',task.patient+' · '+task.office+' · '+form.notes);setForm({...form,patient:''});notify('Verification task added')},complete=t=>{saveTasks(allTasks.map(x=>x.id===t.id?{...x,status:'Completed',completion:today,notes:(x.notes||'')+' | Completed verification: '+today}:x));logActivity&&logActivity('Completed verification',t.patient+' · '+t.office,t.employee);notify('Verification marked complete')};return <><Head k="INSURANCE VERIFICATION" title="Daily verification worksheet" sub="Add verification rows like the Google Sheet, then mark complete when finished."/><Panel title="Add verification row" sub="Use this instead of the manual end-of-day verification sheet."><form className="verification-sheet-form" onSubmit={add}><label>Date<input type="date" value={form.date} onChange={e=>update('date',e.target.value)} required/></label><label>Date of appt.<input type="date" value={form.appt} onChange={e=>update('appt',e.target.value)} required/></label><label>Pt. name<input value={form.patient} onChange={e=>update('patient',e.target.value)} placeholder="Patient name" required/></label><label>Office<select value={form.office} onChange={e=>update('office',e.target.value)}>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Assigned to<select value={form.employee} onChange={e=>update('employee',e.target.value)}>{employees.map(e=><option key={e.id}>{e.name}</option>)}</select></label><label>Notes<select value={form.notes} onChange={e=>update('notes',e.target.value)}>{results.map(r=><option key={r}>{r}</option>)}</select></label><button className="primary"><Plus/>Add task</button></form></Panel><Panel title="Verification rows" sub={tasks.length+' rows for selected filters'}><div className="verification-sheet"><table><thead><tr><th>Date</th><th>Date of appt.</th><th>Pt. name</th><th>Office</th><th>Notes</th><th>Assigned</th><th>Status</th><th></th></tr></thead><tbody>{tasks.map(t=>{const result=(String(t.notes||'').match(/Result: ([^|]+)/)||[])[1]?.trim()||t.notes||'';return <tr key={t.id}><td>{t.due}</td><td>{t.dos}</td><td>{t.patient}</td><td>{t.office}</td><td><em>{result}</em></td><td>{t.employee}</td><td>{t.status}</td><td>{t.status==='Completed'?<button onClick={()=>open(t)}>View</button>:<button className="complete-mini" onClick={()=>complete(t)}>Complete</button>}</td></tr>})}</tbody></table>{!tasks.length&&<div className="empty">No verification rows yet. Add the first patient above.</div>}</div></Panel></>}

function CallsWorksheet({tasks,offices,employees,open,saveTasks,allTasks,notify,logActivity}){const today=new Date().toISOString().slice(0,10),categories=['Inbound Call','Appointment Confirmation','Recall','Follow-up Call','Other'],[form,setForm]=useState({date:today,category:'Inbound Call',patient:'',phone:'',office:offices[0]?.name||'',notes:'',employee:employees[0]?.name||''});const update=(k,v)=>setForm({...form,[k]:v}),field=(notes,label)=>(String(notes||'').match(new RegExp(label+': ([^|\\n]+)'))||[])[1]?.trim()||'',add=e=>{e.preventDefault();if(!form.patient.trim())return notify('Enter patient name');const task={id:'MKG-CALL-'+Date.now(),patient:form.patient.trim(),office:form.office,type:'Calls',employee:form.employee,priority:'Medium',status:'In Progress',due:form.date,dos:form.date,followup:'—',next:form.date,completion:'—',notes:'Category: '+form.category+' | Phone number: '+form.phone+' | Call notes: '+form.notes};saveTasks([task,...allTasks]);logActivity&&logActivity('Added call',task.patient+' · '+form.category+' · '+task.office+' · '+form.phone);setForm({...form,patient:'',phone:'',notes:''});notify('Call task added')},complete=t=>{saveTasks(allTasks.map(x=>x.id===t.id?{...x,type:['Recall Calls','Outbound Calls'].includes(x.type)?'Calls':x.type,status:'Completed',completion:today,notes:(x.notes||'')+' | Completed call: '+today}:x));logActivity&&logActivity('Completed call',t.patient+' · '+t.office,t.employee);notify('Call marked complete')};return <><Head k="CALLS" title="Calls dashboard" sub="Track inbound calls, appointment confirmations, recalls, and follow-up calls together."/><Panel title="Add call row" sub="Choose a category, then enter date, patient, phone, office, and call notes."><form className="verification-sheet-form recall-sheet-form" onSubmit={add}><label>Date<input type="date" value={form.date} onChange={e=>update('date',e.target.value)} required/></label><label>Category<select value={form.category} onChange={e=>update('category',e.target.value)}>{categories.map(c=><option key={c}>{c}</option>)}</select></label><label>Pt. name<input value={form.patient} onChange={e=>update('patient',e.target.value)} placeholder="Patient name" required/></label><label>Phone number<input value={form.phone} onChange={e=>update('phone',e.target.value)} placeholder="(000) 000-0000"/></label><label>Office<select value={form.office} onChange={e=>update('office',e.target.value)}>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Assigned to<select value={form.employee} onChange={e=>update('employee',e.target.value)}>{employees.map(e=><option key={e.id}>{e.name}</option>)}</select></label><label>Call notes<input value={form.notes} onChange={e=>update('notes',e.target.value)} placeholder="Incoming question / confirmed appt / recall message"/></label><button className="primary"><Plus/>Add task</button></form></Panel><Panel title="Call rows" sub={tasks.length+' rows for selected filters'}><div className="verification-sheet recall-sheet"><table><thead><tr><th>Date</th><th>Category</th><th>Pt. name</th><th>Phone number</th><th>Office</th><th>Call notes</th><th>Assigned</th><th>Status</th><th></th></tr></thead><tbody>{tasks.map(t=>{const phone=field(t.notes,'Phone number'),notes=field(t.notes,'Call notes'),category=field(t.notes,'Category')||(t.type==='Recall Calls'?'Recall':t.type==='Outbound Calls'?'Outbound Call':'Call');return <tr key={t.id}><td>{t.due}</td><td>{category}</td><td>{t.patient}</td><td>{phone}</td><td>{t.office}</td><td>{notes}</td><td>{t.employee}</td><td>{t.status}</td><td>{t.status==='Completed'?<button onClick={()=>open(t)}>View</button>:<button className="complete-mini" onClick={()=>complete(t)}>Complete</button>}</td></tr>})}</tbody></table>{!tasks.length&&<div className="empty">No calls yet. Add the first inbound or outbound call above.</div>}</div></Panel></>}

function PreAuthWorksheet({tasks,offices,employees,open,saveTasks,allTasks,notify,logActivity}){const today=new Date().toISOString().slice(0,10),preStatuses=['Pending','Submitted','Approved','Denied','Waiting for Insurance','Need Review','Completed'],[form,setForm]=useState({date:today,patient:'',dos:'',amount:'',office:offices[0]?.name||'',notes:'',status:'Submitted',employee:employees[0]?.name||''});const update=(k,v)=>setForm({...form,[k]:v}),field=(notes,label)=>(String(notes||'').match(new RegExp(label+': ([^|\\n]+)'))||[])[1]?.trim()||'',add=e=>{e.preventDefault();if(!form.patient.trim())return notify('Enter patient name');const done=form.status==='Completed'||form.status==='Approved',task={id:'MKG-PA-'+Date.now(),patient:form.patient.trim(),office:form.office,type:'Pre-Authorization',employee:form.employee,priority:'Medium',status:form.status,due:form.date,dos:form.dos||form.date,followup:form.date,next:form.date,completion:done?today:'—',notes:'Billed amount: '+form.amount+' | Pre-auth notes: '+form.notes};saveTasks([task,...allTasks]);logActivity&&logActivity('Added pre-auth status check',task.patient+' · '+task.office+' · '+form.status,form.employee);setForm({...form,patient:'',dos:'',amount:'',notes:''});notify('Pre-auth status row added')};return <><Head k="PRE-AUTHORIZATION" title="Pre-auth status checked" sub="Add daily pre-auth checks in the same format as your tracking sheet."/><Panel title="Add pre-auth status row" sub="Date, patient, DOS, billed amount, office, notes, and status."><form className="verification-sheet-form" onSubmit={add}><label>Date<input type="date" value={form.date} onChange={e=>update('date',e.target.value)} required/></label><label>Pt. name<input value={form.patient} onChange={e=>update('patient',e.target.value)} required/></label><label>D.O.S<input type="date" value={form.dos} onChange={e=>update('dos',e.target.value)}/></label><label>Billed amount<input value={form.amount} onChange={e=>update('amount',e.target.value)} placeholder="$0.00"/></label><label>Office<select value={form.office} onChange={e=>update('office',e.target.value)}>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Status<select value={form.status} onChange={e=>update('status',e.target.value)}>{preStatuses.map(s=><option key={s}>{s}</option>)}</select></label><label>Assigned to<select value={form.employee} onChange={e=>update('employee',e.target.value)}>{employees.map(e=><option key={e.id}>{e.name}</option>)}</select></label><label>Notes<input value={form.notes} onChange={e=>update('notes',e.target.value)} placeholder="Claim/Auth number, payer update, etc."/></label><button className="primary"><Plus/>Add row</button></form></Panel><Panel title="Pre-auth status rows" sub={tasks.length+' rows for selected filters'}><div className="verification-sheet"><table><thead><tr><th>Date</th><th>Pt. name</th><th>D.O.S</th><th>Billed amount</th><th>Office</th><th>Notes</th><th>Status</th><th></th></tr></thead><tbody>{tasks.map(t=><tr key={t.id}><td>{t.due}</td><td>{t.patient}</td><td>{t.dos}</td><td>{field(t.notes,'Billed amount')}</td><td>{t.office}</td><td>{field(t.notes,'Pre-auth notes')}</td><td>{t.status}</td><td><button onClick={()=>open(t)}>View</button></td></tr>)}</tbody></table>{!tasks.length&&<div className="empty">No pre-auth status checks yet.</div>}</div></Panel></>}

function ClaimStatusWorksheet({tasks,offices,employees,open,saveTasks,allTasks,notify,logActivity}){
 const today=new Date().toISOString().slice(0,10),[form,setForm]=useState({date:today,patient:'',insurance:'',dos:'',amount:'',office:offices[0]?.name||'',notes:'',status:'CHECK CLAIM STATUS',employee:employees[0]?.name||''})
 const update=(k,v)=>setForm({...form,[k]:v}),field=(notes,label)=>(String(notes||'').match(new RegExp(label+': ([^|\\n]+)'))||[])[1]?.trim()||''
 const workedToday=t=>t.followup===today&&(/\[[A-Z][a-z]{2}\s+\d{2},\s+\d{4}/.test(String(t.notes||''))||String(t.notes||'').includes('Status updated from'))
 const checkedRows=tasks.filter(t=>field(t.notes,'Status checked date')||field(t.notes,'Claim status notes')||workedToday(t))
 const activeClaims=tasks.filter(t=>(!t.next||t.next<=today||t.due<=today)&&!workedToday(t))
 const futureClaims=tasks.filter(t=>(t.next&&t.next>today)||workedToday(t))
 const destinationFor=status=>String(status).startsWith('RESUBMITTED')?'Claims Follow-Up':paymentRoutes.includes(status)?'Payment Posting':problemRoutes.includes(status)?'Problem Claims':'Claims Follow-Up'
 const add=e=>{e.preventDefault();if(!form.patient.trim())return notify('Enter patient name');const destination=destinationFor(form.status),days=trackingDueDays[form.status]??(destination==='Claims Follow-Up'?14:null),next=days!=null?addDays(form.date||today,days):form.date,task={id:'MKG-CS-'+Date.now(),patient:form.patient.trim(),office:form.office,type:destination,employee:form.employee,priority:'Medium',status:form.status,due:next,dos:form.dos||form.date,followup:form.date,next,completion:'—',notes:'Insurance: '+form.insurance+' | Billed amount: '+form.amount+' | Claim status notes: '+form.notes+' | Status checked date: '+form.date};saveTasks([task,...allTasks]);logActivity&&logActivity('Added claim tracking status',task.patient+' · '+task.office+' · '+form.status+(destination!=='Claims Follow-Up'?' · moved to '+destination:''),form.employee);setForm({...form,patient:'',insurance:'',dos:'',amount:'',notes:''});notify(destination!=='Claims Follow-Up'?'Claim added and moved to '+destination:'Claim tracking row added')}
 return <><Head k="CLAIMS FOLLOW-UP" title="Claim status checked" sub="New and due claims show in the active queue. Once an employee updates a claim, it moves to review/future follow-up so the active list stays clean."/><Panel title="Add claim status row" sub="Date, patient, insurance, DOS, billed amount, office, notes, and tracking status."><form className="verification-sheet-form" onSubmit={add}><label>Date<input type="date" value={form.date} onChange={e=>update('date',e.target.value)} required/></label><label>Pt. name<input value={form.patient} onChange={e=>update('patient',e.target.value)} required/></label><label>Insurance<input value={form.insurance} onChange={e=>update('insurance',e.target.value)} placeholder="Carrier"/></label><label>DOS<input type="date" value={form.dos} onChange={e=>update('dos',e.target.value)}/></label><label>Billed amount<input value={form.amount} onChange={e=>update('amount',e.target.value)} placeholder="$0.00"/></label><label>Office<select value={form.office} onChange={e=>update('office',e.target.value)}>{offices.map(o=><option key={o.id}>{o.name}</option>)}</select></label><label>Tracking status<select value={form.status} onChange={e=>update('status',e.target.value)}>{claimStatuses.map(s=><option key={s}>{s}</option>)}</select></label><label>Assigned to<select value={form.employee} onChange={e=>update('employee',e.target.value)}>{employees.map(e=><option key={e.id}>{e.name}</option>)}</select></label><label>Notes<input value={form.notes} onChange={e=>update('notes',e.target.value)} placeholder="Claim number, rep, reference, action taken"/></label><button className="primary"><Plus/>Add row</button></form></Panel><LiveDepartment title="Claims Follow-Up due now" tasks={activeClaims} open={open}/><Panel title="QA / updated / future follow-up review" sub={futureClaims.length+' claims hidden from active queue because they were updated today or are waiting for next action date'}><Table tasks={futureClaims} open={open}/></Panel><Panel title="Claim status rows" sub={checkedRows.length+' manually checked or updated claim status rows'}><div className="verification-sheet"><table><thead><tr><th>Date</th><th>Pt. name</th><th>Insurance</th><th>DOS</th><th>Billed amount</th><th>Office</th><th>Notes</th><th>Status</th><th></th></tr></thead><tbody>{checkedRows.map(t=><tr key={t.id}><td>{field(t.notes,'Status checked date')||t.followup}</td><td>{t.patient}</td><td>{field(t.notes,'Insurance')}</td><td>{t.dos}</td><td>{field(t.notes,'Billed amount')}</td><td>{t.office}</td><td>{field(t.notes,'Claim status notes')}</td><td>{t.status}</td><td><button onClick={()=>open(t)}>View</button></td></tr>)}</tbody></table>{!checkedRows.length&&<div className="empty">No manual claim status checks yet. Imported claims stay in the due-now queue until an agent checks/updates them.</div>}</div></Panel></>}
